static int relative_path_stays_beneath(const char *relpath) {
    int depth = 0;
    const char *p = relpath;
    while (*p) {
        while (*p == '/') p++;
        if (!*p) break;
        const char *end = p;
        while (*end && *end != '/') end++;
        size_t clen = (size_t)(end - p);
        if (clen == 1 && p[0] == '.') {
        } else if (clen == 2 && p[0] == '.' && p[1] == '.') {
            depth--;
            if (depth < 0) return 0;
        } else {
            depth++;
        }
        p = end;
    }
    return 1;
}

