{
    return vn && vn->mnt && vn->mnt->root &&
           vn->type == VFS_FT_DIR &&
           vn->ino == vn->mnt->root->ino;
}

static int count_path_components(const char *path)
{
    int n = 0;
    const char *p = path;
    while (*p == '/') p++;
    while (*p) {
        n++;
        while (*p && *p != '/') p++;
        while (*p == '/') p++;
    }
    return n;
}

